#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))

__kernel void hotspot(int iteration,
                      __global float *power,
                      __global float *temp_src,
                      __global float *temp_dst,
                      int cols,
                      int rows,
                      int borderCols,
                      int borderRows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    __local float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __local float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    float amb_temp_local = 80.0f;
    float step_div_Cap;
    float Rx_1, Ry_1, Rz_1;

    int bx = get_group_id(0);
    int by = get_group_id(1);

    int tx = get_local_id(0);
    int ty = get_local_id(1);

    step_div_Cap = step / Cap;

    Rx_1 = 1.0f / Rx;
    Ry_1 = 1.0f / Ry;
    Rz_1 = 1.0f / Rz;

    int small_block_cols = BLOCK_SIZE - iteration * 2;
    int small_block_rows = BLOCK_SIZE - iteration * 2;

    int blkY = small_block_rows * by - borderRows;
    int blkX = small_block_cols * bx - borderCols;
    int blkYmax = blkY + BLOCK_SIZE - 1;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int yidx = blkY + ty;
    int xidx = blkX + tx;

    int index = cols * yidx + xidx;

    if (IN_RANGE(yidx, 0, rows - 1) && IN_RANGE(xidx, 0, cols - 1)) {
        temp_on_cuda[ty][tx] = temp_src[index];
        power_on_cuda[ty][tx] = power[index];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int validYmin = (0 > blkY) ? -blkY : 0;
    int validYmax = (rows - 1 < blkYmax) ? BLOCK_SIZE - 1 - (blkYmax - rows + 1) : BLOCK_SIZE - 1;
    int validXmin = (0 > blkX) ? -blkX : 0;
    int validXmax = (cols - 1 < blkXmax) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (validYmin > N) ? validYmin : N;
    S = (validYmax < S) ? validYmax : S;
    W = (validXmin > W) ? validXmin : W;
    E = (validXmax < E) ? validXmax : E;

    bool computed = false;
    for (int i = 0; i < iteration; i++) {
        computed = false;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, validXmin, validXmax) &&
            IN_RANGE(ty, validYmin, validYmax)) {

            computed = true;
            temp_t[ty][tx] = temp_on_cuda[ty][tx] + step_div_Cap *
                (power_on_cuda[ty][tx] +
                 (temp_on_cuda[S][tx] + temp_on_cuda[N][tx] - 2.0f * temp_on_cuda[ty][tx]) * Ry_1 +
                 (temp_on_cuda[ty][E] + temp_on_cuda[ty][W] - 2.0f * temp_on_cuda[ty][tx]) * Rx_1 +
                 (amb_temp_local - temp_on_cuda[ty][tx]) * Rz_1);
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        if (iteration - 1 == i)
            break;
        if (computed)
            temp_on_cuda[ty][tx] = temp_t[ty][tx];
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        temp_dst[index] = temp_t[ty][tx];
    }
}
